sql:
SELECT SUM(employment_value) AS total_employment
FROM employment_statistics
WHERE occupation_code = '0' AND year = 2023;

SELECT occupation_title
FROM occupations
WHERE employment > 1000;

SELECT AVG(employment_per_region) AS average_employment
FROM occupation_regions
WHERE occupation_code = '1';

SELECT COUNT(occupation_code) AS total_occupations
FROM occupations
WHERE median_hourly_wage > 50;

SELECT median_hourly_wage, mean_hourly_wage
FROM wage_statistics
WHERE year = 2022;

SELECT average_wage
FROM occupation_regions
WHERE occupation_code = '00-0000' AND region_id = 1;

SELECT AVG(annual_mean_wage) AS average_annual_salary
FROM occupations
WHERE occupation_code = '0';

external_knowledge:
- 'Management sector' refers to industry code '11-000'.;
- 'Typical wage ranges' refers to the average median and mean hourly wages. The average employment indicates the size of the workforce.;
- The term 'top five occupations' means the five occupations with the highest average employment values.

sql:
SELECT occupation_code, employment_value, employment_growth_rate
FROM employment_statistics
WHERE year = 2023;

SELECT occupation_code, region_id, average_wage
FROM occupation_regions
ORDER BY average_wage DESC;

SELECT employment
FROM occupations
WHERE occupation_code = '0';

SELECT MAX(annual_mean_wage) AS highest_annual_mean_wage
FROM occupations
WHERE experience_level = 'Mid Level';
